import { PrismaClient, Role, TaskStatus } from "@prisma/client";
import bcrypt from "bcryptjs";

const prisma = new PrismaClient();

async function main() {
  console.log("seeding…");

  await prisma.task.deleteMany();
  await prisma.membership.deleteMany();
