  it("returns tasks whose title contains the search term, case-insensitive", async () => {
    // q='launch' matches "Finalize launch date with marketing", "QA the new signup flow…" (no, that's not 'launch')
    // assert exact match set
  });

  it("returns tasks whose description contains the search term", async () => {
    // seed a task with title='X' description='alpha beta gamma'
    // q='beta' → returns it
  });

  it("matches case-insensitively in both title and description", async () => {
    // q='LAUNCH' returns same rows as q='launch'
  });

  it("returns empty for a search term no row contains", async () => {
    // q='zzz_definitely_not_present' → []
  });

  it("handles Unicode/emoji search terms", async () => {
    // seed a task with title='ship 🚀', search q='🚀' → returns it
  });

  it("matches LIKE-metacharacters (% _) as literals, not wildcards", async () => {
    // seed title='100% done', seed title='all_users_view'
    // q='%' → only matches the first
    // q='_' → only matches the second
    // (Prisma `contains` escapes internally)
  });

  it("returns the same response shape as the non-q branch", async () => {
    const withQ = await GET(/* ?q=Finalize */);
