import { prisma } from "@/lib/prisma";

export { prisma };

/**
 * Look up a seeded user by email. Throws with a helpful message if the seed
 * data isn't present — that's a signal to run `npm run db:seed`.
 */
export async function getSeedUser(email: string) {
  const u = await prisma.user.findFirst({ where: { email } });
  if (!u) {
    throw new Error(
      `seed user not found: ${email} — run \`docker-compose exec web npm run db:seed\``,
    );
  }
  return u;
}

export async function getSeedProject(name: string) {
  const p = await prisma.project.findFirst({ where: { name } });
  if (!p) {
    throw new Error(
      `seed project not found: ${name} — run \`docker-compose exec web npm run db:seed\``,
    );
  }
  return p;
}

