// @vitest-environment node
import { describe, it, expect, beforeAll } from "vitest";
import { GET } from "@/app/api/projects/[id]/tasks/route";
import { prisma, getSeedUser, getSeedProject } from "@/tests/helpers/db";
import { mintToken, newGetRequest, paramsFor } from "@/tests/helpers/http";
import { SQLI_PAYLOADS } from "@/tests/helpers/sqli-payloads";

type SeedUser = { id: string; email: string };
type SeedProject = { id: string };

let dev: SeedUser;
let kavya: SeedUser;
let meera: SeedUser;
let q3: SeedProject;
let onboarding: SeedProject;

beforeAll(async () => {
  dev = await getSeedUser("dev@example.com");
  kavya = await getSeedUser("kavya@example.com");
  meera = await getSeedUser("meera@taskboard.dev");
  q3 = await getSeedProject("Q3 Launch");
  onboarding = await getSeedProject("Customer Onboarding Revamp");
});

async function searchAs(
  user: SeedUser,
  projectId: string,
  q?: string,
): Promise<Response> {
  const params = q !== undefined ? `?q=${encodeURIComponent(q)}` : "";
  const req = newGetRequest(
    `http://localhost/api/projects/${projectId}/tasks${params}`,
    mintToken(user.id, user.email),
  );
  return await GET(req, paramsFor(projectId));
}

// =====================================================================
// §4.1 — Security regressions (must-have, contract of the SQLi fix)
// =====================================================================
describe("GET /api/projects/:id/tasks?q= — SQLi regressions", () => {
  it("[OR 1=1] payload — returns only rows whose title/description literally contain it", async () => {
    const res = await searchAs(dev, q3.id, "%') OR 1=1 -- ");
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.tasks).toEqual([]);
  });

  it("[UNION SELECT FROM users] payload — never returns a bcrypt-hash-shaped string", async () => {
    const payload = `%') UNION SELECT id,email,name,password_hash,NULL::"TaskStatus",NULL,'',0,created_at,updated_at FROM users -- `;
    const res = await searchAs(dev, q3.id, payload);
    expect(res.status).toBe(200);
    const raw = JSON.stringify(await res.json());
    expect(raw).not.toMatch(/\$2[ayb]\$\d+\$[A-Za-z0-9./]{53}/);
  });

  it("[DROP TABLE] payload — treated as a literal search term; tasks table still exists", async () => {
    const before = await prisma.task.count();
    const res = await searchAs(dev, q3.id, "'; DROP TABLE tasks; -- ");
    expect(res.status).toBe(200);
    const after = await prisma.task.count();
    expect(after).toBe(before);
  });

  it.each(SQLI_PAYLOADS)(
    "every known SQLi payload [%s] — response stays scoped to URL's :id",
    async (payload) => {
      const res = await searchAs(dev, q3.id, payload);
      expect(res.status).toBe(200);
      const body = await res.json();
      for (const t of body.tasks) {
        expect(t.projectId).toBe(q3.id);
      }
    },
  );
});

// =====================================================================
// §4.2 — Functional: search still works correctly
// =====================================================================
describe("GET /api/projects/:id/tasks?q= — search behaviour", () => {
  it("matches task titles case-insensitively", async () => {
    const lower = await searchAs(dev, q3.id, "launch");
    const upper = await searchAs(dev, q3.id, "LAUNCH");
    const titlesLower = (await lower.json()).tasks
      .map((t: { title: string }) => t.title)
      .sort();
    const titlesUpper = (await upper.json()).tasks
      .map((t: { title: string }) => t.title)
      .sort();
    expect(titlesLower).toEqual(titlesUpper);
    expect(titlesLower).toContain("Finalize launch date with marketing");
  });

  it("matches against task descriptions", async () => {
    // Seeded tasks all have description="Detail for: <title>" — so this
    // should match every Q3 task via the description branch of the OR.
    const res = await searchAs(dev, q3.id, "Detail for");
    const body = await res.json();
    expect(body.tasks.length).toBeGreaterThan(0);
    for (const t of body.tasks) {
      expect(t.projectId).toBe(q3.id);
    }
  });

  it("returns empty for a search term no row contains", async () => {
    const res = await searchAs(dev, q3.id, "zzz_definitely_not_present_xyz");
    const body = await res.json();
    expect(body.tasks).toEqual([]);
  });

  it("matches LIKE metacharacters (%, _) as literals, not wildcards", async () => {
    // Seeded data has no literal '%' or '_' in titles or descriptions, so
    // these queries must return zero — proving Prisma escaped them.
    const pct = await searchAs(dev, q3.id, "%");
    const underscore = await searchAs(dev, q3.id, "_");
    expect((await pct.json()).tasks).toEqual([]);
    expect((await underscore.json()).tasks).toEqual([]);
  });

  it("returns the same response shape as the non-q branch", async () => {
    const withQ = await searchAs(dev, q3.id, "launch");
    const noQ = await searchAs(dev, q3.id);
    const withQTasks = (await withQ.json()).tasks;
    const noQTasks = (await noQ.json()).tasks;
    expect(withQTasks.length).toBeGreaterThan(0);
    expect(noQTasks.length).toBeGreaterThan(0);

    const keys = (t: object) => Object.keys(t).sort();
    expect(keys(withQTasks[0])).toEqual(keys(noQTasks[0]));
    // Spot-check the key set includes both camelCase columns and the joined assignee.
    expect(keys(withQTasks[0])).toEqual(
      expect.arrayContaining([
        "id",
        "projectId",
        "title",
        "description",
        "status",
        "assigneeId",
        "createdById",
        "position",
        "createdAt",
        "updatedAt",
        "assignee",
      ]),
    );
  });
});

// =====================================================================
// §4.3 — Authorization gate intact
// =====================================================================
describe("GET /api/projects/:id/tasks?q= — authorization", () => {
  it("returns 401 without an Authorization header", async () => {
    const req = newGetRequest(
      `http://localhost/api/projects/${q3.id}/tasks?q=launch`,
    );
    const res = await GET(req, paramsFor(q3.id));
    expect(res.status).toBe(401);
  });

  it("returns 401 for a malformed token", async () => {
    const req = newGetRequest(
      `http://localhost/api/projects/${q3.id}/tasks?q=launch`,
      "not.a.real.token",
    );
    const res = await GET(req, paramsFor(q3.id));
    expect(res.status).toBe(401);
  });

  it("returns 403 when caller is not a member of the project", async () => {
    // dev has zero membership in Customer Onboarding Revamp
    const res = await searchAs(dev, onboarding.id, "launch");
    expect(res.status).toBe(403);
    const body = await res.json();
    expect(body.error).toBe("you are not a member of this project");
  });

  it("allows viewer role to search (search is a read)", async () => {
    // dev's role on Q3 Launch is viewer
    const res = await searchAs(dev, q3.id, "launch");
    expect(res.status).toBe(200);
  });

  it("allows member role to search", async () => {
    // kavya's role on Q3 Launch is member
    const res = await searchAs(kavya, q3.id, "launch");
    expect(res.status).toBe(200);
  });
});

// =====================================================================
// §4.4 — Edge cases
// =====================================================================
describe("GET /api/projects/:id/tasks?q= — edge cases", () => {
  it("missing q falls through to the non-q branch (returns all project tasks)", async () => {
    const res = await searchAs(dev, q3.id);
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.tasks.length).toBeGreaterThan(0);
    for (const t of body.tasks) {
      expect(t.projectId).toBe(q3.id);
    }
  });

  it("empty q ('') falls through to the non-q branch", async () => {
    // The handler's `if (q)` is falsy for "", so the non-q branch runs.
    const empty = await searchAs(dev, q3.id, "");
    const omitted = await searchAs(dev, q3.id);
    const emptyCount = (await empty.json()).tasks.length;
    const omittedCount = (await omitted.json()).tasks.length;
    expect(emptyCount).toBe(omittedCount);
  });

  it("very long q (5000 chars) returns 200, not 500", async () => {
    const longQ = "x".repeat(5000);
    const res = await searchAs(dev, q3.id, longQ);
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.tasks).toEqual([]);
  });

  it("admin multi-project user — search stays scoped to URL's :id", async () => {
    // meera is admin of Q3 AND admin of Internal Tools Cleanup. Searching in
    // Q3 must NOT leak rows from Internal Tools, even though she's entitled
    // to them through a different request.
    const res = await searchAs(meera, q3.id, "Detail for");
    const body = await res.json();
    expect(body.tasks.length).toBeGreaterThan(0);
    for (const t of body.tasks) {
      expect(t.projectId).toBe(q3.id);
    }
  });
});

